import sys

def is_tak_code(grid, i, j):
    # Check top-left 3x3
    for x in range(3):
        for y in range(3):
            if grid[i + x][j + y] != '#':
                return False

    # Check bottom-right 3x3
    for x in range(3):
        for y in range(3):
            if grid[i + 6 + x][j + 6 + y] != '#':
                return False

    # Check adjacent cells around top-left 3x3
    for x in range(3):
        for y in range(3):
            for dx in (-1, 0, 1):
                for dy in (-1, 0, 1):
                    nx = i + x + dx
                    ny = j + y + dy
                    if 0 <= nx < 9 and 0 <= ny < 9:
                        if (nx, ny) not in [(x, y) for x in range(3) for y in range(3)]:
                            if grid[nx][ny] != '.':
                                return False

    # Check adjacent cells around bottom-right 3x3
    for x in range(3):
        for y in range(3):
            for dx in (-1, 0, 1):
                for dy in (-1, 0, 1):
                    nx = i + 6 + x + dx
                    ny = j + 6 + y + dy
                    if 0 <= nx < 9 and 0 <= ny < 9:
                        if (nx, ny) not in [(x, y) for x in range(6, 9) for y in range(6, 9)]:
                            if grid[nx][ny] != '.':
                                return False

    return True

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    M = int(input[1])
    grid = input[2:]

    result = []
    for i in range(N - 8):
        for j in range(M - 8):
            # Extract 9x9 region
            region = [grid[i + x][j:j+9] for x in range(9)]
            if is_tak_code(region, 0, 0):
                result.append((i + 1, j + 1))

    for i, j in result:
        print(f"{i} {j}")

if __name__ == "__main__":
    main()
